766	// reviewXMLEscape escapes &, <, and > for inclusion in XML text content.
767	func reviewXMLEscape(s string) string {
768		var buf bytes.Buffer
769		buf.WriteString(strings.NewReplacer(
770			"&", "&amp;",
771			"<", "&lt;",
772			">", "&gt;",
773		).Replace(s))
774		return buf.String()
775	}
