777	// DefaultBeadReviewer implements BeadReviewer by dispatching the review
778	// invocation through the agent service (or a test-injected runner).
779	// It fetches the bead, builds the review prompt, and runs the reviewer agent.
780	type DefaultBeadReviewer struct {
781		ProjectRoot string
782		BeadStore   BeadReader
783		// Service, when non-nil, is the agentlib.FizeauService used to dispatch the
784		// review invocation. Production callers leave this nil — ReviewBead
785		// constructs a fresh service from ProjectRoot via NewServiceFromWorkDir.
786		Service agentlib.FizeauService
787		// Runner, when non-nil, replaces the service-based dispatch path. Used by
788		// tests to return canned *Result values without spinning up a real
789		// service. Takes precedence over Service.
790		Runner AgentRunner
791		// Harness and Model override the reviewer harness/model.
792		// When Harness is empty, the reviewer follows the implementation harness;
793		// when both are empty, dispatch is left to the agent service.
794		Harness string
795		Model   string
796		// Caps configures the per-section evidence caps used when assembling
797		// the review prompt (FEAT-022). When zero-valued, evidence.DefaultCaps
798		// applies.
799		Caps evidence.Caps
800		// BeadEvents, when non-nil, is used to append the
801		// kind:review-pairing-degraded event when the reviewer's resolved
802		// provider matches the implementer's. Optional: nil disables the
803		// telemetry emission while preserving the rest of the review flow.
804		BeadEvents BeadEventAppender
805		// EventReader, when non-nil, is used to count prior review escalation
806		// triggers (review-error and review-pairing-degraded events) for the
807		// same result_rev so the reviewer MinPower is bumped on retry.
808		EventReader BeadEventReader
809	}
