811	// BuildReviewExecuteRequest constructs the AgentRunRuntime used for the
812	// post-merge reviewer dispatch. It sets the reviewer harness/profile,
813	// attaches the implementer's correlation map (with role=reviewer overlaid),
814	// and derives MinPower as impl.ActualPower + 1 so routing is biased toward a
815	// stronger candidate than the implementer's actual selection. The returned
816	// runtime is missing per-call plumbing (Prompt/PromptFile, WorkDir,
817	// SessionLogDirOverride) — the caller fills those in before dispatching.
818	func BuildReviewExecuteRequest(impl ImplementerRouting, reviewerHarness, reviewerProfile string) AgentRunRuntime {
819		return BuildReviewGroupExecuteRequest(impl, reviewerHarness, reviewerProfile, ReviewGroupDispatchMeta{})
820	}
821	
822	// BuildReviewGroupExecuteRequest constructs the reviewer runtime for one
823	// slot in a review group. It threads the implementer's correlation facts,
824	// overlays reviewer role metadata, and stamps the review_group_id and
825	// reviewer_index when provided so downstream routing / tracing can join the
826	// two reviewer slots back to the same evidence bundle.
827	func BuildReviewGroupExecuteRequest(impl ImplementerRouting, reviewerHarness, reviewerProfile string, meta ReviewGroupDispatchMeta) AgentRunRuntime {
828		correlation := map[string]string{}
829		for k, v := range impl.Correlation {
830			correlation[k] = v
831		}
832		correlation["role"] = "reviewer"
833		if meta.GroupID != "" {
834			correlation["review_group_id"] = meta.GroupID
835			correlation["reviewer_index"] = fmt.Sprintf("%d", meta.ReviewerIndex)
836		}
837		if impl.Harness != "" {
838			correlation["impl_harness"] = impl.Harness
839		}
840		if impl.Provider != "" {
841			correlation["impl_provider"] = impl.Provider
842		}
843		if impl.Model != "" {
844			correlation["impl_model"] = impl.Model
845		}
846		if impl.ActualPower > 0 {
847			correlation["impl_actual_power"] = fmt.Sprintf("%d", impl.ActualPower)
848		}
849		minPower := 0
850		if impl.ActualPower > 0 {
851			minPower = impl.ActualPower + 1
852		}
853		correlationID := reviewCorrelationID(correlation)
854		return AgentRunRuntime{
855			HarnessOverride:     reviewerHarness,
856			ProfileOverride:     reviewerProfile,
857			MinPowerOverride:    minPower,
858			Correlation:         correlation,
859			Role:                "reviewer",
860			CorrelationID:       correlationID,
861			PermissionsOverride: PermissionsReadOnlyReviewer,
862			ClearRoutingPins:    true,
863			ClearProfile:        true,
864			ClearMaxPower:       true,
865		}
866	}
