44	// TestBeadReviewCollapseGolden is the byte-equivalence gate for FEAT-022 §4
45	// stage B: agent.BuildReviewPrompt — which the post-collapse CLI handler
46	// invokes directly — must produce bytes identical to the committed golden
47	// when run against the fixture inputs. The fixture deliberately includes <,
48	// >, &, ", and ' so any divergence in the XML-escape semantics surfaces
49	// here rather than as silent prompt drift.
50	//
51	// Regenerate the golden with: UPDATE_GOLDEN=1 go test -run TestBeadReviewCollapseGolden ./cmd/...
52	func TestBeadReviewCollapseGolden(t *testing.T) {
53		b, refs, rev, diff, root := beadReviewFixture(t)
54		got := agent.BuildReviewPrompt(b, 1, rev, diff, root, refs)
55	
56		goldenPath := filepath.Join("testdata", "bead_review", "collapse_golden.txt")
57		if os.Getenv("UPDATE_GOLDEN") != "" {
58			if err := os.WriteFile(goldenPath, []byte(got), 0o644); err != nil {
59				t.Fatalf("write golden: %v", err)
60			}
61		}
62	
63		want, err := os.ReadFile(goldenPath)
64		if err != nil {
65			t.Fatalf("read golden: %v", err)
66		}
67		if got != string(want) {
68			t.Fatalf("review prompt diverged from golden:\n--- got ---\n%s\n--- want ---\n%s", got, string(want))
69		}
70	
71		for _, ch := range []string{"<", ">", "&", "\"", "'"} {
72			if !strings.Contains(string(want), ch) && !strings.Contains(string(want), xmlEscapeChar(ch)) {
73				t.Errorf("golden must contain XML-escape-sensitive char %q (raw or escaped)", ch)
74			}
75		}
76	}
