78	func xmlEscapeChar(ch string) string {
79		switch ch {
80		case "<":
81			return "&lt;"
82		case ">":
83			return "&gt;"
84		case "&":
85			return "&amp;"
86		case "\"":
87			return "&#34;"
88		case "'":
89			return "&#39;"
90		}
91		return ch
92	}
