// derived from the bead text using the same deterministic checker as
// `ddx doc prose`.
func TestBeadReviewProse_UsesNormalizedDocProseFindings(t *testing.T) {
	b, refs, rev, diff, root := beadReviewFixture(t)
	// Inject AI-slop prose that should trigger a finding
	b.Description = "This robust system creates a seamless workflow. " + b.Description

	prompt := agent.BuildReviewPromptWithProse(b, 1, rev, diff, root, refs)

	if !strings.Contains(prompt, "<prose-review") {
		t.Fatalf("expected prose-review section in prompt, got:\n%s", prompt)
	}
	if !strings.Contains(prompt, "prose.claim.unsupported") {
		t.Fatalf("expected normalized docprose finding with rule_id, got:\n%s", prompt)
	}
	if !strings.Contains(prompt, "robust") {
		t.Fatalf("expected flagged prose content in section, got:\n%s", prompt)
	}
}

// TestBeadReviewProse_EvidenceSeparateFromCorrectnessReview verifies that
// when a <prose-review> section is present, the reviewer agent is instructed
// to output prose_findings separately from correctness findings in the JSON
// response, keeping them advisory.
func TestBeadReviewProse_EvidenceSeparateFromCorrectnessReview(t *testing.T) {
	if _, err := exec.LookPath("git"); err != nil {
		t.Skip("git not available")
	}

	tmp := t.TempDir()
	runGit := func(args ...string) {
		t.Helper()
		c := exec.Command("git", args...)
		c.Dir = tmp
		c.Env = append(os.Environ(),
			"GIT_AUTHOR_NAME=Test", "GIT_AUTHOR_EMAIL=test@example.com",
			"GIT_COMMITTER_NAME=Test", "GIT_COMMITTER_EMAIL=test@example.com",
		)
		if out, err := c.CombinedOutput(); err != nil {
			t.Fatalf("git %s: %v: %s", strings.Join(args, " "), err, out)
		}
	}
	runGit("init", "-q")
	runGit("config", "user.email", "test@example.com")
	runGit("config", "user.name", "Test")
	if err := os.WriteFile(filepath.Join(tmp, "x.go"), []byte("package x\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	runGit("add", "x.go")
	runGit("commit", "-q", "-m", "init")
	c := exec.Command("git", "rev-parse", "HEAD")
	c.Dir = tmp
	shaOut, err := c.Output()
	if err != nil {
		t.Fatalf("rev-parse: %v", err)
	}
	sha := strings.TrimSpace(string(shaOut))

	ddxDir := filepath.Join(tmp, ddxroot.DirName)
	if err := os.MkdirAll(ddxDir, 0o755); err != nil {
		t.Fatal(err)
	}
	store := bead.NewStore(ddxDir)
	if err := store.Init(); err != nil {
		t.Fatalf("store init: %v", err)
	}
	b := &bead.Bead{
		ID:          "ddx-prose-sep",
		Title:       "test prose separation",
		Description: "This robust system enables better collaboration seamlessly.",
		Acceptance:  "AC#1: verify the code is correct",
		Extra:       map[string]any{"closing_commit_sha": sha},
	}
	if err := store.Create(b); err != nil {
		t.Fatalf("store create: %v", err)
	}
	if err := store.Update("ddx-prose-sep", func(bd *bead.Bead) {
		if bd.Extra == nil {
			bd.Extra = map[string]any{}
		}
		bd.Extra["closing_commit_sha"] = sha
	}); err != nil {
		t.Fatalf("update: %v", err)
	}

	factory := NewCommandFactory(tmp)
	cmd := factory.newBeadReviewCommand()
	var stdout bytes.Buffer
	cmd.SetOut(&stdout)
	cmd.SetErr(&stdout)
	cmd.SetArgs([]string{"ddx-prose-sep", "--prose"})
	if err := cmd.ExecuteContext(context.Background()); err != nil {
		t.Fatalf("execute: %v\noutput: %s", err, stdout.String())
	}

	out := stdout.String()

	// Verify the prompt contains the instruction about separating prose findings
	if !strings.Contains(out, "prose_findings") {
		t.Fatalf("expected prose_findings keyword in prompt instructions, got:\n%s", out)
	}
	if !strings.Contains(out, "Keep prose findings separate from correctness findings") {
		t.Fatalf("expected separation instruction, got:\n%s", out)
	}
	// Verify both prose review section and correctness review flow exist
	if !strings.Contains(out, "<prose-review") {
		t.Fatalf("expected prose-review section, got:\n%s", out)
	}
	if !strings.Contains(out, "<bead-review>") {
		t.Fatalf("expected bead-review correctness section, got:\n%s", out)
	}
}

