// TestBeadReviewProse_UsesNormalizedDocProseFindings verifies that the
// bead review prompt with --prose includes normalized docprose findings
// derived from the bead text using the same deterministic checker as
// `ddx doc prose`.
func TestBeadReviewProse_UsesNormalizedDocProseFindings(t *testing.T) {
	b := &bead.Bead{
		ID:          "ddx-prose-norm",
		Title:       "test normalized findings",
		Description: "This robust system creates a seamless workflow enabling better collaboration.",
		Acceptance:  "AC#1: verify implementation",
	}
	refs := []GoverningRef{
		{ID: "FEAT-001", Path: "docs/spec.md", Title: "Test Spec"},
	}
	rev := "abc123"
	diff := "diff --git a/test.go b/test.go\nindex 0..1\n--- a/test.go\n+++ b/test.go\n@@ -1 +1,2 @@\n package x\n+func New() {}"

	prompt := BuildReviewPromptWithProse(b, 1, rev, diff, t.TempDir(), refs)

	// Verify prose review section is included
	if !strings.Contains(prompt, "<prose-review") {
		t.Fatalf("expected prose-review section in prompt, got:\n%s", prompt)
	}
	// Verify Vale-backed rule IDs are present
	if !strings.Contains(prompt, "prose.claim.unsupported") {
		t.Fatalf("expected normalized docprose finding with Vale-backed rule_id, got:\n%s", prompt)
	}
	// Verify the flagged prose content is identified
	if !strings.Contains(prompt, "robust") && !strings.Contains(prompt, "seamless") {
		t.Fatalf("expected flagged prose content in section, got:\n%s", prompt)
	}
	// Verify advisory mode is set
	if !strings.Contains(prompt, "advisory=\"true\"") {
		t.Fatalf("expected advisory=\"true\" in prose-review section, got:\n%s", prompt)
	}
}

// TestBeadReviewProse_EvidenceSeparateFromCorrectnessReview verifies that
// when a <prose-review> section is present, the reviewer agent is instructed
// to output prose_findings separately from correctness findings in the JSON
// response, keeping them advisory.
func TestBeadReviewProse_EvidenceSeparateFromCorrectnessReview(t *testing.T) {
	b := &bead.Bead{
		ID:          "ddx-prose-sep",
		Title:       "test evidence separation",
		Description: "This robust system enables better collaboration seamlessly.",
		Acceptance:  "AC#1: verify implementation",
	}
	refs := []GoverningRef{}
	rev := "def456"
	diff := "diff --git a/test.go b/test.go\nindex 0..1\n--- a/test.go\n+++ b/test.go\n@@ -1 +1,2 @@\n package x"

	prompt := BuildReviewPromptWithProse(b, 1, rev, diff, t.TempDir(), refs)

	// Verify both bead review (correctness) and prose review sections are present
	if !strings.Contains(prompt, "<bead id=") {
		t.Fatalf("expected bead correctness section in prompt")
	}
	if !strings.Contains(prompt, "<prose-review") {
		t.Fatalf("expected prose-review advisory section in prompt")
	}

	// Verify the instructions mention prose_findings separation
	if !strings.Contains(prompt, "prose_findings") {
		t.Fatalf("expected prose_findings keyword in prompt instructions")
	}
	if !strings.Contains(prompt, "Keep prose findings separate from correctness findings") {
		t.Fatalf("expected separation instruction in prompt")
	}
	if !strings.Contains(prompt, "Prose findings are advisory by default") {
		t.Fatalf("expected advisory instruction in prompt")
	}
}

